```cpp
#include <iostream>

__global__ void kernel(double* x, double* y, double* out) {
  *out = floor(pow(*x, *y));
}

int main() {
  double x = 3.0;
  double y = 1.0;
  double out;
  double* x_dev;
  double* y_dev;
  double* out_dev;
  cudaMalloc(&x_dev, sizeof(double));
  cudaMalloc(&y_dev, sizeof(double));
  cudaMalloc(&out_dev, sizeof(double));
  cudaMemcpy(x_dev, &x, sizeof(double), cudaMemcpyHostToDevice);
  cudaMemcpy(y_dev, &y, sizeof(double), cudaMemcpyHostToDevice);
  kernel<<<1, 1>>>(x_dev, y_dev, out_dev);
  cudaMemcpy(&out, out_dev, sizeof(double), cudaMemcpyDeviceToHost);
  std::cout << out << std::endl;
  return 0;
}
